  const $$ = (selector, root = document) => Array.from(root.querySelectorAll(selector));
  const esc = (value = '') => String(value).replace(/[&<>"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
  const svg = (id, cls = '') => `<svg class="${cls}" aria-hidden="true"><use href="#i-${id}"/></svg>`;
  const money = value => new Intl.NumberFormat('en-US', { style:'currency', currency:'USD', maximumFractionDigits: value % 1 ? 2 : 0 }).format(Number(value || 0));
  const shortMoney = value => value >= 1000 ? `$${(value / 1000).toFixed(value >= 10000 ? 0 : 1)}k` : money(value);
  const parseDate = value => value instanceof Date ? value : new Date(`${String(value).slice(0,10)}T${String(value).includes('T') ? String(value).split('T')[1] : '12:00:00'}`);
  const isoDate = date => { const d = new Date(date); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`; };
  const dateAt = (offset, hour = 9, minute = 0) => { const d = new Date(); d.setHours(hour, minute, 0, 0); d.setDate(d.getDate() + offset); return `${isoDate(d)}T${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}:00`; };
  const dateOnly = offset => { const d = new Date(); d.setHours(12,0,0,0); d.setDate(d.getDate() + offset); return isoDate(d); };
  const dateLabel = (value, options = {}) => new Intl.DateTimeFormat('en-US', { month:'short', day:'numeric', year: options.year ? 'numeric' : undefined, ...options }).format(new Date(value));
  const timeLabel = value => new Intl.DateTimeFormat('en-US', { hour:'numeric', minute:'2-digit' }).format(new Date(value));
  const dateTimeLabel = value => `${dateLabel(value)} · ${timeLabel(value)}`;
  const initials = name => String(name || '').split(/\s+/).map(p => p[0]).join('').slice(0,2).toUpperCase();
  const uid = prefix => `${prefix}-${Math.floor(1000 + Math.random() * 9000)}`;
  const titleCase = value => String(value || '').replace(/-/g,' ').replace(/\b\w/g, c => c.toUpperCase());
  const plural = (count, singular, multiple = `${singular}s`) => `${count} ${count === 1 ? singular : multiple}`;
  const daysBetween = (start, end) => Math.max(1, Math.ceil((new Date(end) - new Date(start)) / 86400000));
  const isSameDay = (a,b) => isoDate(new Date(a)) === isoDate(new Date(b));
  const overlap = (aStart,aEnd,bStart,bEnd) => new Date(aStart) < new Date(bEnd) && new Date(aEnd) > new Date(bStart);
  const clone = value => JSON.parse(JSON.stringify(value));
